<template>
  <div class="dropdown" tabindex="0" @click="expandMenu()" @blur="collapseMenu()">
    <p>
      {{ engineList[selectedIndex].name }}
      <span class="dropIcon">&gt;</span>
    </p>
    <ul v-show="isShow">
      <li
        v-for="(item, i) in engineList"
        :key="item.id"
        :class="{active: selectedIndex === i}"
        @click="selectItem(item, i)"
      >{{ item.name }}</li>
    </ul>
  </div>
</template>

<script>
export default {
  props: {
    engineList: {
      type: Array,
      required: true,
      default() { return [{id: '', name: '', base: ''}]}
    }
  },

  data() { return {
    selectedIndex: NaN,
    isShow: false
  }},

  methods: {
    expandMenu(el) {
      this.isShow = !this.isShow;
    },
    collapseMenu() {
      this.isShow = false;
    },
    selectItem(item, index) {
      this.selectedIndex = index;
      localStorage.setItem('engineIndex', index);
      this.$emit('select-engine', index);
    }
  },

  created() {
    if (localStorage.getItem('engineIndex')) {
      this.selectedIndex = +localStorage.getItem('engineIndex');
    } else {
      this.selectedIndex = 0;
    }
    this.selectItem(this.engineList[this.selectedIndex], this.selectedIndex);
  }
}
</script>

<style lang="scss" scoped>
@import '@/common/_public.scss';

div.dropdown {
  display: inline-block;
  position: relative;
  color: $content;
  cursor: pointer;

  p {
    box-sizing: border-box;
    max-width: 20em;
    overflow: hidden;
    line-height: 1em;
    @include padding(0.5, 1);
    @include border(0.25);
  }
  span.dropIcon {
    display: inline-block;
    color: $subtext;
    transform-origin: center 55%;
    transform: rotate(90deg) scale(0.9, 1.5);
  }
  ul {
    position: absolute;
    top: ($sz-normal * 2.5);
    max-height: ($sz-normal * 1.5 * 6);
    overflow-y: auto;
    background: #ffffff;
    @include border(0.25);
    @include box-shadow(0, 1, 1.5, -0.75, #e4e0cb);
    transform-origin: center top; 
    animation: vertical-expand 400ms 1;

    li {
      box-sizing: border-box;
      line-height: 1.5em;
      white-space: pre;
      @include padding(0, 1);
    }

    li.active {
      background: $lighthigh;
    }
  }
}

</style>