import Vue from 'vue'
import VueRouter from 'vue-router'
import Home from '../views/Home'

Vue.use(VueRouter)

const routes = [
  {
    name: 'home',
    path: '/',
    component: Home
  },
  {
    name: 'bookmarks',
    path: '/bookmarks',
    component: () => import('../views/Bookmarks')
  },
  {
    name: 'laterview',
    path: '/laterview',
    component: () => import('../views/LaterView')
  },
  {
    name: 'resttime',
    path: '/resttime',
    component: () => import('../views/RestTime')
  },
  {
    name: 'todo',
    path: '/todo',
    component: () => import('../views/Todo')
  },
  {
    path: '*',
    redirect: {
      name: 'home'
    }
  },
]

const router = new VueRouter({
  routes
})

export default router
