<template>
  <div class="searchEngine">
    <form class="search">
      <div>
        <input type="text" name="searchContent" v-model="content" placeholder="想搜点什么呢？" autocomplete="off">
      </div>
      <div class="controller">
        <dropdown :engineList="engineList" @select-engine="handleEngine($event)"></dropdown>
        <button type="submit" @click.prevent="handleSearch()">Go</button>
      </div>
    </form>
  </div>
</template>

<script>
import Dropdown from './Dropdown';

export default {
  components: {
    'dropdown': Dropdown
  },

  data() { return {
    content: '',
    engineList: [
      { id: 'dogedoge', name: '多吉 ★', base: 'https://www.dogedoge.com/results?q=%keyword%'},
      { id: 'bing', name: '必应', base: 'https://cn.bing.com/search?q=%keyword%'},
      { id: 'sogou', name: '搜狗', base: 'https://www.sogou.com/web?query=%keyword%'},
      { id: 'baidu', name: '百度', base: 'https://www.baidu.com/s?wd=%keyword%'},
      { id: 'zhihu', name: '知乎', base: 'https://www.zhihu.com/search?type=content&q=%keyword%'},
      { id: 'weibo', name: '微博', base: 'https://s.weibo.com/weibo/%keyword%'},
      { id: 'bilibili', name: '哔哩哔哩', base: 'https://search.bilibili.com/all?keyword=%keyword%'},
      { id: 'youtube', name: 'YouTube', base: 'https://www.youtube.com/results?search_query=%keyword%'},
      { id: 'duckduckgo', name: 'DuckDuckGo', base: 'https://duckduckgo.com/?q=%keyword%'},
      { id: 'google', name: 'Google', base: 'https://www.google.com/search?q=%keyword%'},
      { id: 'github', name: 'GitHub', base: 'https://github.com/search?q=%keyword%'},
      { id: 'caniuse', name: 'CanIuse', base: 'https://caniuse.com/#search=%keyword%'},
      { id: 'wordsmyth', name: 'Wordsmyth', base: 'https://www.wordsmyth.net/?level=2&ent=%keyword%'},
      { id: 'hujiangdict', name: '沪江小D', base: 'https://dict.hjenglish.com/w/%keyword%'},
      { id: 'huaban', name: '花瓣', base: 'https://huaban.com/search/?q=%keyword%'},
      { id: 'hellorf', name: '站酷', base: 'https://www.hellorf.com/image/search?q=%keyword%'}
    ],
    engineIndex: NaN
  }},

  methods: {
    handleEngine(index) {
      this.engineIndex = index;
    },
    handleSearch() {
      let base = this.engineList[this.engineIndex].base,
        url = base.replace(/%keyword%/, this.content);
      
      window.open(url);
    }
  }
}
</script>

<style lang="scss" scoped>
@import '@/common/_public.scss';

div.searchEngine {
  box-sizing: border-box;
  width: 100%;
  max-width: 480px;
  margin: 0 auto;

  input {
    display: block;
    box-sizing: border-box;
    width: 100%;
    background: transparent;
    color: $subtext;
    font-size: $sz-normal;
    line-height: $sz-normal;
    @include padding(0.5, 1);
    border: 0;
    border-bottom: 1px solid $shadow;
    border-radius: ($sz-normal / 4);
    @include margin(2, 0);
    margin-top: ($sz-normal * 9);
  }

  div.controller {
    display: flex;
    flex-flow: row wrap;
    justify-content: space-between;

    button {
      box-sizing: border-box;
      background: $primary;
      color: #ffffff;
      font-size: $sz-normal;
      line-height: $sz-normal;
      @include padding(0.5, 0.5);
      border: 1px solid transparent;
      border-radius: ($sz-normal / 4);
      cursor: pointer;
    }
  }
}

</style>